function toggleMob(){document.getElementById('mobMenu').classList.toggle('open');}
function closeMob(){document.getElementById('mobMenu').classList.remove('open');}

// PRICING TABS
function showTab(id,btn){
  document.querySelectorAll('.ppanel').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.ptab').forEach(t=>t.classList.remove('active'));
  document.getElementById('tab-'+id).classList.add('active');
  btn.classList.add('active');
}

// EMAIL BOOKING VIA FORMSPREE
const bookingForm = document.getElementById('bookingForm');
if (bookingForm) {
  bookingForm.addEventListener('submit', function(e){
    e.preventDefault();
    const btn = document.getElementById('bookingSubmitBtn');
    const originalBtnHTML = btn.innerHTML;
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Sending...';

    fetch(bookingForm.action, {
      method: 'POST',
      body: new FormData(bookingForm),
      headers: { 'Accept': 'application/json' }
    }).then(response => {
      if (response.ok) {
        bookingForm.style.display = 'none';
        document.getElementById('formTitle').style.display = 'none';
        document.getElementById('bookingSuccess').style.display = 'block';
      } else {
        response.json().then(data => {
          alert((data.errors && data.errors.map(e=>e.message).join(', ')) || 'Something went wrong. Please try again or WhatsApp us directly.');
          btn.disabled = false;
          btn.innerHTML = originalBtnHTML;
        });
      }
    }).catch(() => {
      alert('Network error. Please try again or WhatsApp us directly.');
      btn.disabled = false;
      btn.innerHTML = originalBtnHTML;
    });
  });
}

// SCROLL REVEAL
function observeReveal(){
  const obs=new IntersectionObserver(entries=>{
    entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('vis');});
  },{threshold:0.1});
  document.querySelectorAll('.reveal:not(.vis)').forEach(el=>obs.observe(el));
}
observeReveal();

// BACK TO TOP
window.addEventListener('scroll',()=>{
  const bt=document.getElementById('bktop');
  bt.classList.toggle('show',window.scrollY>280);
});

// PARTICLES
(function(){
  const cv=document.getElementById('pcv');
  const ctx=cv.getContext('2d');
  let W,H,pts=[];
  function resize(){W=cv.width=window.innerWidth;H=cv.height=window.innerHeight;}
  resize();window.addEventListener('resize',resize);
  const cols=['rgba(255,79,154,','rgba(126,200,255,','rgba(216,241,255,','rgba(255,214,231,','rgba(212,160,79,'];
  for(let i=0;i<60;i++)pts.push({x:Math.random()*W,y:Math.random()*H,r:Math.random()*3.5+1.2,vx:(Math.random()-.5)*.45,vy:(Math.random()-.5)*.38,c:cols[Math.floor(Math.random()*cols.length)],a:Math.random()*.38+.08});
  function draw(){
    ctx.clearRect(0,0,W,H);
    pts.forEach(p=>{
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle=p.c+p.a+')';ctx.fill();
      p.x+=p.vx;p.y+=p.vy;
      if(p.x<0)p.x=W;if(p.x>W)p.x=0;if(p.y<0)p.y=H;if(p.y>H)p.y=0;
    });
    requestAnimationFrame(draw);
  }
  draw();
})();